"""Tests for Claude Code integration file generation.

Tests that `osprey init` generates Claude Code integration files
(.mcp.json, CLAUDE.md, .claude/ hooks).
"""

import json
import os

import pytest
import yaml
from click.testing import CliRunner

from osprey.cli.init_cmd import init
from osprey.cli.templates.manager import TemplateManager


class TestClaudeCodeIntegrationDefault:
    """Test that Claude Code files are generated by default."""

    def test_default_init_creates_all_claude_code_files(self, tmp_path):
        """Default init creates all Claude Code files."""
        manager = TemplateManager()
        project_dir = manager.create_project(
            project_name="test-project",
            output_dir=tmp_path,
            template_name="control_assistant",
        )

        # All core files should exist
        assert (project_dir / ".mcp.json").exists()
        assert (project_dir / "CLAUDE.md").exists()
        assert (project_dir / ".claude" / "settings.json").exists()
        assert (project_dir / ".claude" / "rules" / "safety.md").exists()
        assert (project_dir / ".claude" / "rules" / "error-handling.md").exists()
        assert (project_dir / ".claude" / "hooks" / "osprey_writes_check.py").exists()
        assert (project_dir / ".claude" / "hooks" / "osprey_limits.py").exists()
        assert (project_dir / ".claude" / "hooks" / "osprey_approval.py").exists()
        assert (project_dir / ".claude" / "hooks" / "osprey_error_guidance.py").exists()

    def test_claude_code_always_generated(self, tmp_path):
        """Claude Code files are always generated (single mode)."""
        manager = TemplateManager()
        project_dir = manager.create_project(
            project_name="always-claude-project",
            output_dir=tmp_path,
            template_name="control_assistant",
        )

        assert (project_dir / ".mcp.json").exists()
        assert (project_dir / "CLAUDE.md").exists()
        assert (project_dir / ".claude").exists()


class TestClaudeCodeFileContents:
    """Test the contents of generated Claude Code files."""

    @pytest.fixture()
    def project_dir(self, tmp_path):
        manager = TemplateManager()
        return manager.create_project(
            project_name="content-test",
            output_dir=tmp_path,
            template_name="control_assistant",
        )

    def test_mcp_json_is_valid_json(self, project_dir):
        """.mcp.json is valid JSON with expanded project path."""
        mcp_path = project_dir / ".mcp.json"
        data = json.loads(mcp_path.read_text())

        assert "mcpServers" in data
        # Core OSPREY servers
        assert "controls" in data["mcpServers"]
        assert "workspace" in data["mcpServers"]

        import sys

        # Control system server
        cs = data["mcpServers"]["controls"]
        assert cs["command"] == sys.executable
        assert cs["args"] == ["-m", "osprey.mcp_server.control_system"]
        expected_config = f"{project_dir}/config.yml"
        assert cs["env"]["OSPREY_CONFIG"] == expected_config

        # Workspace server
        ws = data["mcpServers"]["workspace"]
        assert ws["args"] == ["-m", "osprey.mcp_server.workspace"]

    def test_settings_json_has_hooks_and_permissions(self, project_dir):
        """.claude/settings.json has hooks and permissions."""
        settings_path = project_dir / ".claude" / "settings.json"
        data = json.loads(settings_path.read_text())

        assert "permissions" in data
        assert "allow" in data["permissions"]
        assert "ask" in data["permissions"]
        # channel_read is hook-managed (not in allow) so all_capabilities mode works
        assert "mcp__controls__channel_read" not in data["permissions"]["allow"]
        assert "mcp__controls__channel_write" in data["permissions"]["ask"]
        # channel_read has a PreToolUse matcher for dynamic approval
        pre_matchers = [h["matcher"] for h in data["hooks"]["PreToolUse"]]
        assert "mcp__controls__channel_read" in pre_matchers
        assert "mcp__workspace__submit_response" in data["permissions"]["allow"]

        assert "hooks" in data
        assert "PreToolUse" in data["hooks"]
        assert "PostToolUse" in data["hooks"]

    def test_settings_json_denies_filesystem_tools(self, project_dir):
        """Built-in filesystem/shell tools are denied; Task delegated to ask.

        Write is intentionally NOT denied — Claude Code's native auto memory
        system requires Write access to persist memories across sessions.
        """
        settings_path = project_dir / ".claude" / "settings.json"
        data = json.loads(settings_path.read_text())

        deny = data["permissions"]["deny"]
        assert "Bash" in deny
        assert "Edit" in deny
        assert "Write" not in deny  # auto memory needs Write
        assert "WebFetch" in deny
        assert "WebSearch" in deny

        # NotebookEdit moved to allow (restricted to artifacts dir)
        assert "NotebookEdit" not in deny
        allow = data["permissions"]["allow"]
        assert any("NotebookEdit" in a for a in allow)

        # Channel-finder tools not in deny (server is agent-exclusive via inline mcpServers)
        assert "mcp__channel-finder__*" not in deny

        # Task not denied; agent Tasks are conditionally allowed
        # Generic "Task" removed from ask so it doesn't override specific allow rules
        assert "Task" not in deny
        assert "Task" not in data["permissions"]["ask"]
        # channel-finder only present when channel_finder_pipeline is defined
        assert "Task(logbook-search)" in data["permissions"]["allow"]

        # Stale channel_find entry removed from allow
        assert "mcp__controls__channel_find" not in data["permissions"]["allow"]

        # Read should not be in bare allow (only scoped Read(...) entries)
        allow = data["permissions"]["allow"]
        assert "Read" not in allow
        assert "Glob" not in allow
        assert "Grep" not in allow

        # Scoped Read entries should exist
        scoped_reads = [entry for entry in allow if entry.startswith("Read(")]
        assert len(scoped_reads) > 0

    def test_settings_json_hooks_are_structurally_valid(self, project_dir):
        """Every hook entry in PreToolUse/PostToolUse has a 'hooks' array."""
        settings_path = project_dir / ".claude" / "settings.json"
        data = json.loads(settings_path.read_text())

        for hook_type in ["PreToolUse", "PostToolUse"]:
            entries = data["hooks"].get(hook_type, [])
            for i, entry in enumerate(entries):
                assert "hooks" in entry, f"{hook_type}[{i}] missing 'hooks' array: {entry}"
                assert isinstance(entry["hooks"], list), (
                    f"{hook_type}[{i}]['hooks'] is not a list: {type(entry['hooks'])}"
                )

    def test_mcp_json_has_no_sentinel_entries(self, project_dir):
        """mcp.json should not contain sentinel/placeholder server entries."""
        mcp_data = json.loads((project_dir / ".mcp.json").read_text())
        for key in mcp_data["mcpServers"]:
            assert "sentinel" not in key.lower(), f"Sentinel entry '{key}' found in mcpServers"

    def test_hook_scripts_are_executable(self, project_dir):
        """Hook scripts have executable permissions."""
        hooks_dir = project_dir / ".claude" / "hooks"
        hook_files = [
            "osprey_writes_check.py",
            "osprey_limits.py",
            "osprey_approval.py",
            "osprey_memory_guard.py",
        ]
        for hook_name in hook_files:
            hook_path = hooks_dir / hook_name
            assert hook_path.exists(), f"Hook {hook_name} should exist"
            mode = os.stat(hook_path).st_mode
            assert mode & 0o111, f"Hook {hook_name} should be executable"

    def test_settings_local_json_not_included(self, project_dir):
        """settings.local.json (dev-only) is NOT included."""
        assert not (project_dir / ".claude" / "settings.local.json").exists()

    def test_claude_md_has_identity_and_agents(self, project_dir):
        """CLAUDE.md has forceful identity and agent roster."""
        content = (project_dir / "CLAUDE.md").read_text()
        assert "never fabricated" in content
        assert "## Agents" in content
        assert "Delegate" in content

    def test_claude_md_has_no_configuration_section(self, project_dir):
        """CLAUDE.md does not expose internal configuration details."""
        content = (project_dir / "CLAUDE.md").read_text()
        assert "## Configuration" not in content
        assert "config.yml" not in content

    def test_safety_rules_md_loads_unconditionally(self, project_dir):
        """safety.md has no paths restriction (loads at startup, not conditionally)."""
        content = (project_dir / ".claude" / "rules" / "safety.md").read_text()
        assert "paths:" not in content
        assert "_agent_data" in content

    def test_safety_rules_md_has_confinement(self, project_dir):
        """safety.md includes MCP-only confinement and channel write safety."""
        content = (project_dir / ".claude" / "rules" / "safety.md").read_text()
        assert "EXCLUSIVELY through MCP tools" in content
        assert "Channel Write Safety" in content
        assert "NEVER write to control system channels" in content
        assert "never work around failures" in content


